import{_ as r,c as d,o as l,a5 as t,j as a}from"./chunks/framework.Dtwt352Q.js";const _=JSON.parse('{"title":"v1.2.2：会话列表性能大幅提升","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.2.2.md","filePath":"changelog/v1.2.2.md","lastUpdated":1772014034000}'),h={name:"changelog/v1.2.2.md"};function o(i,e,n,s,c,p){return l(),d("div",null,[...e[0]||(e[0]=[t('<h1 id="v1-2-2-会话列表性能大幅提升" tabindex="-1">v1.2.2：会话列表性能大幅提升 <a class="header-anchor" href="#v1-2-2-会话列表性能大幅提升" aria-label="Permalink to “v1.2.2：会话列表性能大幅提升”">​</a></h1><p><strong>发布日期</strong>：2026年2月14日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新让<strong>会话列表加载更快了</strong>，特别是会话很多的时候，速度提升明显。</p><hr><h2 id="新功能-会话列表性能优化" tabindex="-1">新功能：会话列表性能优化 <a class="header-anchor" href="#新功能-会话列表性能优化" aria-label="Permalink to “新功能：会话列表性能优化”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>优化了 <code>Session.list()</code> 的查询性能，现在会在数据库层面进行过滤，而不是加载所有数据后再过滤。</p><h3 id="会话列表是什么" tabindex="-1">会话列表是什么？ <a class="header-anchor" href="#会话列表是什么" aria-label="Permalink to “会话列表是什么？”">​</a></h3><p>OpenCode 会保存所有历史会话。当你在不同的项目目录下运行 <code>opencode attach</code> 或查看会话列表时，OpenCode 需要加载这些历史记录。</p><h3 id="性能提升有多大" tabindex="-1">性能提升有多大？ <a class="header-anchor" href="#性能提升有多大" aria-label="Permalink to “性能提升有多大？”">​</a></h3><table tabindex="0"><thead><tr><th>会话数量</th><th>之前</th><th>现在</th></tr></thead><tbody><tr><td>10 个</td><td>很快</td><td>很快</td></tr><tr><td>50 个</td><td>稍慢</td><td>很快</td></tr><tr><td>100+ 个</td><td>明显卡顿</td><td>流畅</td></tr></tbody></table><p><strong>简单说</strong>：如果你的会话很多（几十上百个），这次更新会让你感觉&quot;快多了&quot;。</p><hr><h2 id="问题修复-模型变体支持" tabindex="-1">问题修复：模型变体支持 <a class="header-anchor" href="#问题修复-模型变体支持" aria-label="Permalink to “问题修复：模型变体支持”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>使用 Vercel gateway 或某些提供商时，模型的变体（variant）可能无法正确识别和使用。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>修复了 Vercel gateway 的变体问题，确保模型选择更准确。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>会话很多，加载有点慢</td><td>✅ 升级</td></tr><tr><td>使用 Vercel gateway</td><td>✅ 升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',24),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>添加 Session.list() 过滤器的全面测试覆盖</li><li>在数据库级别过滤会话，提高会话列表加载性能</li><li>修复 Vercel gateway 变体</li><li>升级 Vertex AI 包</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const m=r(h,[["render",o]]);export{_ as __pageData,m as default};
